import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { HiCode, HiLightningBolt, HiShieldCheck } from 'react-icons/hi';

const FOCUSES = [
  {
    icon: HiLightningBolt,
    title: 'Agentic AI Systems',
    desc: 'LangGraph multi-agent pipelines with investigation, compliance, and reasoning agents operating over RAG knowledge bases.',
    color: 'text-[#6c63ff]',
    bg: 'bg-[#6c63ff]/10',
    border: 'border-[#6c63ff]/20',
  },
  {
    icon: HiShieldCheck,
    title: 'Financial AI & AML',
    desc: 'End-to-end fraud detection combining rule engines, statistical anomaly detection, ensemble ML, and GNN fraud ring discovery.',
    color: 'text-[#38bdf8]',
    bg: 'bg-[#38bdf8]/10',
    border: 'border-[#38bdf8]/20',
  },
  {
    icon: HiCode,
    title: 'Causal Inference',
    desc: 'DoWhy DAG construction and EconML meta-learners for treatment effect estimation and uplift modelling on behavioral data.',
    color: 'text-emerald-400',
    bg: 'bg-emerald-500/10',
    border: 'border-emerald-500/20',
  },
];

const QUICK_FACTS = [
  { key: 'Location', val: 'Bangalore, India' },
  { key: 'University', val: 'JAIN University · B.Tech CS AI/ML' },
  { key: 'CGPA', val: '7.8 / 10.0' },
  { key: 'Status', val: 'Open to full-time roles', highlight: true },
  { key: 'Focus', val: 'AML · LLM Safety · Causal Inference' },
  { key: 'Email', val: 'hanaharis95@gmail.com' },
];

export default function About() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });

  return (
    <section id="about" className="py-28 px-6 bg-[#080810]">
      <div className="max-w-7xl mx-auto" ref={ref}>
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <span className="font-mono text-[#6c63ff] text-sm tracking-widest uppercase">// about</span>
          <h2 className="font-space text-4xl md:text-5xl font-bold text-white mt-3 mb-4">
            Who I Am
          </h2>
        </motion.div>

        {/* Bio + Quick facts */}
        <div className="grid lg:grid-cols-2 gap-12 items-start mb-16">
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.7, delay: 0.1 }}
          >
            <p className="text-slate-300 text-lg leading-relaxed mb-5">
              I'm an AI/ML Engineer based in{' '}
              <span className="text-white font-medium">Bangalore, India</span>, building
              production-grade intelligent systems at the intersection of machine learning,
              LLM toolchains, and financial crime prevention.
            </p>
            <p className="text-slate-400 leading-relaxed mb-5">
              My work spans the full stack of modern AI — from data engineering and
              feature pipelines to ensemble ML, graph neural networks, and LangGraph
              agentic frameworks. I design systems that don't just predict, but{' '}
              <span className="text-[#a78bfa] font-medium">reason, investigate, and explain</span>.
            </p>
            <p className="text-slate-400 leading-relaxed">
              Currently pursuing B.Tech in Computer Science (AI &amp; ML) at{' '}
              <span className="text-white font-medium">JAIN University</span> with a
              CGPA of 7.8, while building real-world enterprise-grade AI systems in
              parallel. Open to full-time AI/ML engineering roles globally.
            </p>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: 30 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.7, delay: 0.2 }}
            className="space-y-3"
          >
            {QUICK_FACTS.map(({ key, val, highlight }) => (
              <div
                key={key}
                className="flex items-center gap-4 px-5 py-3.5 rounded-xl border border-white/[0.05] bg-white/[0.02]"
              >
                <span className="font-mono text-xs text-slate-500 uppercase tracking-widest w-24 shrink-0">
                  {key}
                </span>
                <span className={`text-sm font-medium ${highlight ? 'text-emerald-400' : 'text-slate-300'}`}>
                  {highlight && (
                    <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-400 mr-2 animate-pulse" />
                  )}
                  {val}
                </span>
              </div>
            ))}
          </motion.div>
        </div>

        {/* Focus areas */}
        <div className="grid md:grid-cols-3 gap-5">
          {FOCUSES.map((f, i) => {
            const Icon = f.icon;
            return (
              <motion.div
                key={f.title}
                initial={{ opacity: 0, y: 25 }}
                animate={isInView ? { opacity: 1, y: 0 } : {}}
                transition={{ duration: 0.5, delay: 0.3 + i * 0.12 }}
                className={`p-6 rounded-2xl border ${f.border} ${f.bg}`}
              >
                <Icon size={24} className={`${f.color} mb-4`} />
                <h3 className="font-space font-semibold text-white mb-2">{f.title}</h3>
                <p className="text-slate-400 text-sm leading-relaxed">{f.desc}</p>
              </motion.div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
